def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about astronauts (or related entities) into a
    fluent English sentence.  This version builds a richer description that
    links astronaut triples with mission details, producing a single complex
    sentence whenever possible.
    """
    if not triples:
        return ""

    # Normalise object strings
    def clean(obj: str) -> str:
        return obj.strip().strip('"')

    # Helper to format dates
    def fmt_date(d: str) -> str:
        try:
            from datetime import datetime
            dt = datetime.strptime(d, "%Y-%m-%d")
            return dt.strftime("%B %-d, %Y")
        except Exception:
            return d

    # Collect mission‑specific information
    mission_info = {}
    for t in triples:
        pred = t.predicate.lower().replace(" ", "")
        if t.subject not in mission_info:
            mission_info[t.subject] = {}
        if pred in {"operator", "backuppilot", "commander", "crewmembers"}:
            mission_info[t.subject][pred] = clean(t.object)

    # Collect astronaut information
    astronauts = {}
    for t in triples:
        pred = t.predicate.lower().replace(" ", "")
        subj = t.subject
        if pred == "mission":
            astronauts.setdefault(subj, {"mission": clean(t.object)})
        elif pred in {"birthdate", "birthplace", "deathdate", "deathplace",
                      "nationality", "occupation", "status", "selectedbynasa",
                      "timeinspace", "title", "award", "awards", "ribbonaward",
                      "alternativename", "servedaschiefoftheastronautofficein"}:
            astronauts.setdefault(subj, {"descriptors": []})
            astronauts[subj].setdefault("descriptors", []).append((pred, clean(t.object)))

    # Build sentences for each astronaut
    sentences = []
    for astronaut, info in astronauts.items():
        parts = []

        # Mission clause
        mission = info.get("mission")
        if mission:
            mission_clause = f"was a crew member of {mission}"
            # add operator if known
            op = mission_info.get(mission, {}).get("operator")
            if op:
                mission_clause += f" operated by {op}"
            # add backup pilot if known
            bp = mission_info.get(mission, {}).get("backuppilot")
            if bp:
                mission_clause += f", with {bp} as the backup pilot"
            # add commander if known
            cmd = mission_info.get(mission, {}).get("commander")
            if cmd:
                mission_clause += f", commanded by {cmd}"
            parts.append(mission_clause)

        # Other descriptors
        for pred, obj in info.get("descriptors", []):
            if pred == "birthdate":
                parts.append(f"was born on {fmt_date(obj)}")
            elif pred == "birthplace":
                parts.append(f"was born in {obj}")
            elif pred == "deathdate":
                parts.append(f"died on {fmt_date(obj)}")
            elif pred == "deathplace":
                parts.append(f"died in {obj}")
            elif pred == "nationality":
                low = obj.lower()
                if low in ("united states", "usa", "united states of america"):
                    parts.append("is an American")
                elif low.startswith("the "):
                    parts.append(f"is from {obj}")
                else:
                    parts.append(f"is from the {obj}")
            elif pred == "occupation":
                parts.append(f"was a {obj.lower()}")
            elif pred == "status":
                low = obj.lower()
                parts.append("is retired" if low == "retired" else f"is {low}")
            elif pred == "selectedbynasa":
                parts.append(f"was selected by NASA in {obj}")
            elif pred == "timeinspace":
                try:
                    mins = float(obj)
                    hrs = int(mins // 60)
                    rem = int(mins % 60)
                    if hrs:
                        time_str = f"{hrs} hour{'s' if hrs > 1 else ''}"
                        if rem:
                            time_str += f" and {rem} minute{'s' if rem != 1 else ''}"
                    else:
                        time_str = f"{rem} minute{'s' if rem != 1 else ''}"
                    parts.append(f"spent {time_str} in space")
                except Exception:
                    parts.append(f"spent {obj} minutes in space")
            elif pred == "title":
                parts.append(f"held the title of {obj}")
            elif pred == "award":
                parts.append(f"received the {obj}")
            elif pred == "awards":
                parts.append(f"received {obj} awards")
            elif pred == "ribbonaward":
                parts.append(f"was awarded the {obj}")
            elif pred == "alternativename":
                parts.append(f"is also known as {obj}")
            elif pred == "servedaschiefoftheastronautofficein":
                parts.append(f"served as Chief of the Astronaut Office in {obj}")

        # Combine parts into a sentence
        if parts:
            sentence = f"{astronaut} " + ", ".join(parts) + "."
            sentences.append(sentence)

    # Combine sentences for different subjects
    return " ".join(sentences)

# EVOLVE-BLOCK-END

